                      setDriverPassword(e.target.value);
                      setDriverError('');
                    }}
                    placeholder="••••••"
                    className="w-full bg-slate-700 border border-slate-600 rounded-md p-3 focus:ring-amber-500 focus:border-amber-500 text-center text-lg"
                    required
                  />
