          fare: parseFloat(fare),
          specificDriverId: specificDriverId ? parseInt(specificDriverId, 10) : undefined,
          scheduledTime: scheduledTime || undefined,
        },
      });
      setPickup('');
      setDestination('');
      setTime('');
      setFare('');
      setSpecificDriverId('');
      setScheduledTime('');
    }
  };

  const handleAddDriver = (e: React.FormEvent) => {
    e.preventDefault();
    if(newDriverName && newDriverUnit && newDriverVehicle) {
        dispatch({
            type: 'ADD_DRIVER',
            payload: { 
              name: newDriverName, 
              unitNumber: newDriverUnit, 
              vehicleModel: newDriverVehicle, 
              password: newDriverPassword || '123' 
            }
        });
        setNewDriverName('');
        setNewDriverUnit('');
        setNewDriverVehicle('');
        setNewDriverPassword('');
    }
  };

   const handleEditDriver = (driver: Driver) => {
    dispatch({ type: 'EDIT_DRIVER', payload: driver });
    setEditingDriver(null);
  };

  const handleRemoveDriver = (driverId: number) => {
      if (window.confirm('Tem certeza que deseja remover este motorista?')) {
          dispatch({ type: 'REMOVE_DRIVER', payload: { driverId } });
      }
  };

  const handleChangePassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) {
      setPasswordStatus({ type: 'error', message: 'As senhas não coincidem.' });
      return;
    }
    dispatch({ type: 'CHANGE_ADMIN_PASSWORD', payload: { newPassword } });
    setPasswordStatus({ type: 'success', message: 'Senha administrativa atualizada!' });
    setNewPassword('');
    setConfirmPassword('');
    setTimeout(() => setPasswordStatus(null), 3000);
  };

  const ridesByStatus = (status: RideStatus) =>
    state.rides.filter(ride => ride.status === status);

  const availableDrivers = state.drivers
    .filter(d => d.isAvailable)
    .sort((a, b) => a.position - b.position);

  return (
    <>
      {editingDriver && (
        <EditDriverModal 
            driver={editingDriver} 
            onClose={() => setEditingDriver(null)}
            onSave={handleEditDriver}
        />
      )}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 flex flex-col gap-6">
          {/* Nova Corrida - Acessível para Admin e SuperAdmin */}
          <div className="bg-slate-800 rounded-lg shadow-lg p-6 border border-slate-700">
            <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
              <PlusCircleIcon className="w-7 h-7 text-amber-400" />
              Nova Corrida
            </h2>
            <form onSubmit={handleSubmitRide} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-300 mb-1">Embarque</label>
                <input type="text" value={pickup} onChange={(e) => setPickup(e.target.value)} placeholder="Ex: Av. Paulista, 1000" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500" required />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-300 mb-1">Destino</label>
                <input type="text" value={destination} onChange={(e) => setDestination(e.target.value)} placeholder="Ex: Aeroporto de Congonhas" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500" required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Horário</label>
                  <input type="time" value={time} onChange={(e) => setTime(e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Valor (R$)</label>
                  <input type="number" value={fare} onChange={(e) => setFare(e.target.value)} step="0.01" placeholder="35.50" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500" required />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-300 mb-1">Atribuir a motorista específico</label>
                 <select value={specificDriverId} onChange={(e) => setSpecificDriverId(e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500">
                    <option value="">Próximo da Fila (Disponível)</option>
                    {state.drivers.map(d => (
                        <option key={d.id} value={d.id}>
                            {d.position}. {d.name} (Un. {d.unitNumber})
                        </option>
                    ))}
                 </select>
              </div>
              <button type="submit" className="w-full bg-amber-500 hover:bg-amber-600 text-slate-900 font-bold py-2 px-4 rounded-md transition duration-300">
                Publicar Corrida
              </button>
            </form>
          </div>

          {/* Fila de Atendimento Imediato - Destaque das unidades disponíveis */}
          <div className="bg-slate-800 rounded-lg shadow-lg p-6 border border-emerald-500/30">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-2 text-emerald-400">
                  <RocketIcon className="w-6 h-6" />
                  Atendimento Imediato
              </h2>
              <div className="space-y-2 max-h-60 overflow-y-auto pr-2">
                  {availableDrivers.length > 0 ? availableDrivers.map((driver, index) => (
                      <div key={driver.id} className="flex items-center justify-between bg-emerald-500/10 p-3 rounded-md border border-emerald-500/20">
                          <div className="flex items-center gap-3">
                              <span className="font-black text-emerald-400 text-xl w-6 text-center">{index + 1}º</span>
                              <div>
                                  <p className="font-bold text-slate-100">Un. {driver.unitNumber}</p>
                                  <p className="text-xs text-slate-400 truncate w-32">{driver.name}</p>
                              </div>
                          </div>
                          <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded font-bold">ONLINE</span>
                      </div>
                  )) : (
                      <p className="text-slate-500 text-sm italic text-center py-4">Nenhuma unidade disponível para chamado.</p>
                  )}
              </div>
          </div>

          {/* Gestão de Unidades - Exclusivo SuperAdmin */}
          {accessLevel === 'superadmin' && (
              <div className="bg-slate-800 rounded-lg shadow-lg p-6 border border-slate-700">
                  <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
                      <UsersIcon className="w-7 h-7 text-amber-400" />
                      Administração Geral
                  </h2>
                  <form onSubmit={handleAddDriver} className="space-y-4 mb-6">
                      <p className="text-xs text-slate-400">Cadastrar nova unidade no sistema:</p>
                      <input type="text" value={newDriverName} onChange={(e) => setNewDriverName(e.target.value)} placeholder="Nome do Motorista" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500 text-sm" required />
                      <div className="grid grid-cols-2 gap-3">
                          <input type="text" value={newDriverUnit} onChange={(e) => setNewDriverUnit(e.target.value)} placeholder="Nº Unidade" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500 text-sm" required />
                          <input type="text" value={newDriverPassword} onChange={(e) => setNewDriverPassword(e.target.value)} placeholder="Senha" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 focus:ring-amber-500 focus:border-amber-500 text-sm" required />
                      </div>
                      <button type="submit" className="w-full bg-sky-600 hover:bg-sky-700 text-white font-bold py-2 px-4 rounded-md transition duration-300 text-sm">
                          Incluir Nova Unidade
                      </button>
                  </form>

                  <h3 className="text-sm font-semibold mb-3 text-slate-400 uppercase tracking-widest">Controle de Unidades</h3>
                  <div className="space-y-2 max-h-64 overflow-y-auto pr-2">
                      {state.drivers.sort((a,b) => a.position - b.position).map(driver => (
                          <div key={driver.id} className="flex items-center justify-between bg-slate-700/50 p-3 rounded-md border border-slate-600/50">
                              <div className="flex items-center gap-2">
                                  <span className="font-bold text-amber-400 w-5">{driver.position}</span>
                                  <div>
                                      <p className="font-semibold text-slate-100 text-sm">Un. {driver.unitNumber}</p>
                                      <p className="text-[10px] text-slate-500 truncate w-24">{driver.name}</p>
                                  </div>
                              </div>
                              <div className="flex items-center gap-1">
                                  <button onClick={() => setEditingDriver(driver)} className="p-1.5 text-slate-400 hover:text-amber-500 transition-colors">
                                      <PencilIcon className="w-4 h-4"/>
                                  </button>
                                  <button onClick={() => handleRemoveDriver(driver.id)} className="p-1.5 text-slate-400 hover:text-rose-500 transition-colors">
                                      <XCircleIcon className="w-4 h-4"/>
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>

                  <div className="mt-8 pt-6 border-t border-slate-700">
                    <h3 className="text-sm font-bold text-slate-100 mb-4 flex items-center gap-2">
                        <LockIcon className="w-4 h-4 text-amber-400" />
