                    </h3>
                    <form onSubmit={handleChangePassword} className="space-y-3">
                        <input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="Nova senha Admin" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-xs" required />
                        <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="Confirmar senha" className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-xs" required />
                        {passwordStatus && <p className="text-[10px] text-emerald-400">{passwordStatus.message}</p>}
                        <button type="submit" className="w-full bg-slate-600 hover:bg-slate-500 text-white font-bold py-2 rounded-md transition duration-300 text-xs">
                            Alterar Senha Administrativa
