import React, { useEffect, useRef } from 'react';
import { useAppState } from '../hooks/useAppState';
import { Driver, RideStatus } from '../types';
import RideCard from './RideCard';
import { BellIcon, CheckCircleIcon, CoffeeIcon, TrophyIcon, XCircleIcon, RocketIcon, PowerIcon, UserIcon } from './Icons';

interface DriverViewProps {
  driver: Driver;
}

const DriverView: React.FC<DriverViewProps> = ({ driver }) => {
  const { state, dispatch } = useAppState();
  const audioContextRef = useRef<AudioContext | null>(null);

  const availableRides = state.rides.filter(r => r.status === RideStatus.WAITING);
  const currentRide = state.rides.find(r => r.assignedDriverId === driver.id && r.status === RideStatus.IN_PROGRESS);
  const isAnyRideOfferedToMe = availableRides.some(r => r.offeredToDriverId === driver.id);

  // Filtra motoristas disponíveis para saber a posição na fila de atendimento imediato
  const driversOnline = state.drivers
    .filter(d => d.isAvailable)
    .sort((a, b) => a.position - b.position);

  const positionInAvailability = driversOnline.findIndex(d => d.id === driver.id) + 1;

  const playNotificationSound = () => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();
      oscillator.type = 'sine';
      oscillator.frequency.setValueAtTime(880, ctx.currentTime);
      oscillator.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.5);
      gainNode.gain.setValueAtTime(0.1, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);
      oscillator.connect(gainNode);
      gainNode.connect(ctx.destination);
      oscillator.start();
      oscillator.stop(ctx.currentTime + 0.5);
    } catch (e) {
      console.warn("Som não pôde ser reproduzido:", e);
    }
  };

  useEffect(() => {
    if (isAnyRideOfferedToMe) {
        playNotificationSound();
    }
  }, [isAnyRideOfferedToMe]);

  const handleToggleAvailability = () => {
    dispatch({ type: 'TOGGLE_DRIVER_AVAILABILITY', payload: { driverId: driver.id } });
  }

  const handleAcceptRide = (rideId: string) => {
    dispatch({ type: 'ACCEPT_RIDE', payload: { rideId, driverId: driver.id } });
  };

  const handleDeclineRide = (rideId: string) => {
    dispatch({ type: 'DECLINE_RIDE', payload: { rideId, driverId: driver.id } });
  };

  const handleCompleteRide = (rideId: string) => {
    dispatch({ type: 'COMPLETE_RIDE', payload: { rideId } });
  };

  const completedRidesCount = state.rides.filter(r => r.assignedDriverId === driver.id && r.status === RideStatus.COMPLETED).length;

  return (
    <div className="space-y-6">
       <div className="bg-slate-800 rounded-lg shadow-lg p-6 border border-slate-700">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                <div className="flex items-center gap-6">
                    <div className="relative">
                        <div className={`w-20 h-20 rounded-full border-4 flex items-center justify-center text-3xl font-black ${driver.isAvailable ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-rose-500/10 border-rose-500 text-rose-400'}`}>
                            {driver.isAvailable ? positionInAvailability : '-'}
                        </div>
                        {driver.isAvailable && (
                            <div className="absolute -bottom-2 -right-2 bg-emerald-500 text-slate-900 text-[10px] font-bold px-2 py-1 rounded-full border-2 border-slate-800">
                                FILA ONLINE
                            </div>
                        )}
                    </div>
                    <div>
                        <h2 className="text-2xl font-bold text-slate-100">
                            {driver.isAvailable ? `Próximo da Fila: ${positionInAvailability}º` : 'Você está Offline'}
                        </h2>
                        <p className="text-slate-400 text-sm">
                            Sua posição geral na cooperativa é <span className="text-amber-400 font-bold">{driver.position}º</span>
                        </p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
                    <div className="flex items-center gap-2 text-emerald-400 bg-emerald-500/10 py-2 px-4 rounded-full border border-emerald-500/30">
                        <TrophyIcon className="w-5 h-5" />
                        <span className="font-bold">{completedRidesCount}</span>
                        <span className="text-xs">finalizadas</span>
                    </div>
                    <button
                        onClick={handleToggleAvailability}
                        className={`flex items-center gap-2 font-black py-3 px-8 rounded-lg transition-all duration-300 w-full sm:w-auto justify-center shadow-xl transform active:scale-95 ${
                            driver.isAvailable
                                ? 'bg-rose-600 hover:bg-rose-700 text-white'
                                : 'bg-emerald-500 hover:bg-emerald-600 text-white'
                        }`}
                    >
                        <PowerIcon className="w-6 h-6" />
                        <span>{driver.isAvailable ? 'ENCERRAR TURNO' : 'INICIAR ATENDIMENTO'}</span>
                    </button>
                </div>
            </div>
            {!driver.isAvailable && (
                <div className="mt-4 p-3 bg-amber-500/10 border border-amber-500/20 rounded-md text-amber-300 text-sm text-center">
                    Atenção: Você não receberá novos chamados enquanto estiver offline.
                </div>
            )}
       </div>

      {currentRide && (
        <div className="animate-pulse-slow">
          <h3 className="text-xl font-bold mb-3 text-sky-400 flex items-center gap-2 uppercase tracking-wider">
            <RocketIcon className="w-6 h-6"/>
            Corrida em Atendimento
          </h3>
          <RideCard ride={currentRide}>
            <div className="mt-6">
              <button
                onClick={() => handleCompleteRide(currentRide.id)}
                className="w-full bg-emerald-500 hover:bg-emerald-600 text-slate-900 font-black py-4 px-4 rounded-lg transition duration-300 flex items-center justify-center gap-2 text-lg shadow-xl"
              >
                <CheckCircleIcon className="w-6 h-6"/>
                FINALIZAR CORRIDA
              </button>
            </div>
          </RideCard>
        </div>
      )}

      <div>
        <h3 className="text-xl font-bold mb-3 text-slate-100 flex items-center gap-2 uppercase tracking-wider">
            <BellIcon className={`w-6 h-6 ${isAnyRideOfferedToMe ? 'text-amber-400 animate-bounce' : 'text-slate-600'}`}/>
            Chamados Disponíveis
        </h3>
        {availableRides.some(r => r.offeredToDriverId === driver.id) ? (
          <div className="space-y-4">
            {availableRides.filter(r => r.offeredToDriverId === driver.id).map(ride => (
              <div key={ride.id} className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-r from-amber-500 to-yellow-500 rounded-lg blur opacity-25 group-hover:opacity-50 transition duration-1000 group-hover:duration-200"></div>
                <div className="relative">
                  <RideCard ride={ride}>
                    <div className="mt-6 flex flex-col sm:flex-row gap-4">
                      <button
                        onClick={() => handleAcceptRide(ride.id)}
                        className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-slate-900 font-black py-4 px-4 rounded-lg transition duration-300 flex items-center justify-center gap-2 text-lg shadow-lg"
                      >
                        <CheckCircleIcon className="w-6 h-6"/>
                        ACEITAR
                      </button>
                      <button
                        onClick={() => handleDeclineRide(ride.id)}
                        className="flex-1 bg-slate-700 hover:bg-rose-600 text-white font-bold py-4 px-4 rounded-lg transition duration-300 flex items-center justify-center gap-2 shadow-lg"
                      >
                        <XCircleIcon className="w-5 h-5"/>
                        RECUSAR
                      </button>
                    </div>
                  </RideCard>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-16 bg-slate-800/40 rounded-xl border-2 border-dashed border-slate-700">
            <CoffeeIcon className="w-16 h-16 mx-auto text-slate-600 mb-4"/>
            <p className="text-slate-400 text-lg">Sem novos chamados no momento.</p>
            <p className="text-slate-500 text-sm">Você será notificado assim que sua vez chegar.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default DriverView;

import React, { useState } from 'react';
import { AppStateProvider, useAppState } from './hooks/useAppState';
import AdminView from './components/AdminView';
import DriverView from './components/DriverView';
import Header from './components/Header';
import LoginView from './components/LoginView';
import { Driver } from './types';

const AppContent: React.FC = () => {
  const { state } = useAppState();
  const [currentUser, setCurrentUser] = useState<string | number | null>(null);

  const loggedInDriver: Driver | null =
    typeof currentUser === 'number'
      ? state.drivers.find(d => d.id === currentUser) || null
      : null;

  if (!currentUser) {
    return <LoginView onLogin={setCurrentUser} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Header
        currentUser={currentUser}
        loggedInDriver={loggedInDriver}
        onLogout={() => setCurrentUser(null)}
      />
      <main className="flex-grow container mx-auto p-4 md:p-6">
        {(currentUser === 'admin' || currentUser === 'superadmin') ? (
          <AdminView accessLevel={currentUser as any} />
        ) : (
          loggedInDriver && <DriverView driver={loggedInDriver} />
        )}
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AppStateProvider>
      <AppContent />
    </AppStateProvider>
  );
};

export default App;

import React from 'react';
import { Driver } from '../types';
import { CarIcon, UserIcon, LogOutIcon, UsersIcon } from './Icons';

interface HeaderProps {
  currentUser: string | number;
  loggedInDriver: Driver | null;
  onLogout: () => void;
}

const Header: React.FC<HeaderProps> = ({ currentUser, loggedInDriver, onLogout }) => {
  const getDisplayName = () => {
    if (currentUser === 'superadmin') {
      return 'Administrador Geral';
    }
    if (currentUser === 'admin') {
      return 'Painel Operacional';
    }
    if (loggedInDriver) {
      return `Olá, ${loggedInDriver.name}`;
    }
    return '';
  };

  return (
    <header className="bg-slate-800/50 backdrop-blur-sm sticky top-0 z-10 shadow-md border-b border-slate-700/50">
      <div className="container mx-auto px-4 md:px-6 py-3 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <CarIcon className="w-8 h-8 text-amber-400" />
          <h1 className="text-2xl font-bold text-white tracking-tight">
            Cootramo <span className="text-amber-400">Digital</span>
          </h1>
        </div>
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 text-right">
                {currentUser === 'superadmin' ? (
                  <UsersIcon className="w-5 h-5 text-sky-400 hidden sm:block" />
                ) : (
                  <UserIcon className="w-5 h-5 text-slate-400 hidden sm:block" />
                )}
                <div>
                  <span className={`font-semibold ${currentUser === 'superadmin' ? 'text-sky-400' : 'text-slate-100'}`}>
                    {getDisplayName()}
                  </span>
                  {loggedInDriver && <span className="text-xs text-slate-400 block sm:inline sm:ml-2">(Un. {loggedInDriver.unitNumber})</span>}
                </div>
            </div>
            <button
                onClick={onLogout}
                className="flex items-center gap-2 bg-slate-700 hover:bg-rose-600/50 text-slate-300 hover:text-rose-300 font-semibold py-2 px-3 rounded-md transition-colors duration-300"
                aria-label="Sair"
            >
                <LogOutIcon className="w-5 h-5" />
                <span className="hidden sm:inline">Sair</span>
            </button>
        </div>
      </div>
    </header>
  );
