                >
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${idx === 0 ? 'bg-amber-500 text-slate-900' : 'bg-slate-600 text-slate-300'}`}>
                      {idx + 1}º
                    </span>
                    <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
