              ))}
              {availableDrivers.length === 0 && (
                <div className="col-span-full py-6 text-center border-2 border-dashed border-slate-700 rounded-xl">
                  <p className="text-slate-500 text-sm italic">Nenhum motorista online no momento.</p>
