                  {ridesByStatus(RideStatus.SCHEDULED).length === 0 && <p className="text-slate-500 italic text-sm">Nenhuma corrida aguardando horário.</p>}
                </div>
              </div>

              <div>
                <h3 className="text-xl font-semibold mb-3 text-amber-400 flex items-center gap-2">
                    <UsersIcon className="w-5 h-5"/>
                    Disponíveis para Aceite ({ridesByStatus(RideStatus.WAITING).length})
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {ridesByStatus(RideStatus.WAITING).map(ride => (
                    <RideCard key={ride.id} ride={ride} />
                  ))}
                  {ridesByStatus(RideStatus.WAITING).length === 0 && <p className="text-slate-500 italic text-sm">Nenhuma corrida aguardando motorista.</p>}
                </div>
              </div>

              <div>
                <h3 className="text-xl font-semibold mb-3 text-sky-400 flex items-center gap-2">
                    <RocketIcon className="w-5 h-5"/>
                    Corridas em Curso ({ridesByStatus(RideStatus.IN_PROGRESS).length})
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {ridesByStatus(RideStatus.IN_PROGRESS).map(ride => (
                    <RideCard key={ride.id} ride={ride} />
                  ))}
                </div>
              </div>

              <div>
                <h3 className="text-xl font-semibold mb-3 text-emerald-400 flex items-center gap-2">
                    <CheckCircleIcon className="w-5 h-5"/>
                    Histórico Recente
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 opacity-75">
                  {ridesByStatus(RideStatus.COMPLETED).slice(0, 4).map(ride => (
                    <RideCard key={ride.id} ride={ride} />
