type Action =
  | { type: 'HYDRATE'; payload: Omit<AppState, '_isHydrated'> }
  | { type: 'ADD_RIDE'; payload: Omit<Ride, 'id' | 'status'> & { specificDriverId?: number; scheduledTime?: string } }
  | { type: 'ACCEPT_RIDE'; payload: { rideId: string; driverId: number } }
